// // This module is designed to be a 3-bit synchronous binary down counter.
module counter3bit (
    input wire clk,
    input wire rst,
    output reg [2:0] q
);

    always @(posedge clk or posedge rst) begin
        if (rst)
            q <= 3'b000;
        else
            q <= q + 1;
    end

endmodule
